  ),
  resolved AS (
    SELECT s.id AS state_id, v.justia_url, v.document_type, v.topic, v.industry, v.facility_type,
           v.universal_scope, v.universal_scope_checked
    FROM v JOIN states s ON s.slug = v.state_slug
  ),
  upd AS (
    UPDATE laws AS l
    SET document_type = r.document_type,
        topic = r.topic,
        industry = r.industry,
        facility_type = r.facility_type,
        universal_scope = r.universal_scope,
        metadata_classified_at = NOW(),
        universal_scope_classified_at = CASE WHEN r.universal_scope_checked THEN NOW() ELSE l.universal_scope_classified_at END
    FROM resolved r
    WHERE l.state_id = r.state_id AND l.justia_url = r.justia_url
    RETURNING l.id
  )
  SELECT count(*) INTO updated_count FROM upd;

  RAISE NOTICE 'Local rows: % | Matched and updated in production: %', local_row_count, updated_count;

  IF updated_count < expected_min THEN
    RAISE EXCEPTION 'Only % of % local rows matched (below the % minimum) — aborting without committing. This means production''s laws table has drifted from local (different scrape run, edited/removed rows, etc.). Investigate before re-running; do not lower the threshold just to force a commit.', updated_count, local_row_count, expected_min;
  END IF;
END $$;

-- --- 3. Manually-verified full-text corrections (see MANUALLY_CORRECTED_CITATIONS
--        in generateProductionMergeScript.mjs) — warns but does not abort the
--        transaction if a specific citation doesn't match production. ---
DO $$
DECLARE
  updated_count INTEGER;
BEGIN
  UPDATE laws AS l
  SET description = '(a) This chapter applies to a structure constructed on or after January 1, 2017, or a structure that is modified, renovated, or tenant improved on or after January 1, 2020, that is one of the following occupancy types under the California Building Standards Code:
(1) A Group A occupancy (assembly) with an occupant load greater than 300.
(2) A Group B occupancy (business) with an occupant load of 200 or more.
(3) A Group E occupancy (educational) with an occupant load of 200 or more.
(4) A Group F occupancy (factory/industrial) with an occupant load of 200 or more.
(5) A Group I occupancy (institutional) with an occupant load of 200 or more.
(6) A Group M occupancy (mercantile) with an occupant load of 200 or more.
(7) A Group R occupancy (residential, excluding single-family and multifamily dwelling units) with an occupant load of 200 or more.
(b) For purposes of this chapter, a structure is "modified, renovated, or tenant improved" if the modification, renovation, or tenant improvement, in a single calendar year, has a value of one hundred thousand dollars ($100,000) or more, or is any tenant improvement for a place of assembly, including an auditorium or a performing arts or movie theater.
(c) A structure described in subdivision (a) or (b) that is an occupied structure shall have an automated external defibrillator (AED) on the premises subject to the requirements in Section 1797.196. A person or entity that acquires an AED for emergency care pursuant to this section shall not be liable for any civil damages resulting from any acts or omissions in the rendering of the emergency care by use of an AED if that person or entity has complied with subdivision (b) of Section 1797.196.
(d) This section does not apply to a structure owned or operated by a local government entity, or to a health facility licensed pursuant to Section 1250, 1250.2, 1250.3, or 1250.8.
(e) If there is an existing AED in the common area of the structure, the requirements of this section are met without the installation of another AED.
(f) This section does not apply to a structure, or portion of a structure, that is vacant or under construction.',
